#!/usr/bin/env python3

import subprocess
import sys
import os
import json
import hashlib
import re
from pathlib import Path
from typing import List, Dict, Set, Optional, Tuple
from datetime import datetime
import argparse


class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.requirements_lock = self.project_root / "requirements.lock"
        self.requirements_dev = self.project_root / "requirements-dev.txt"
        self.pyproject_toml = self.project_root / "pyproject.toml"
        self.poetry_lock = self.project_root / "poetry.lock"
        
    def detect_dependency_manager(self) -> str:
        if self.poetry_lock.exists() or self.pyproject_toml.exists():
            return "poetry"
        elif self.requirements_file.exists():
            return "pip"
        else:
            return "unknown"
    
    def generate_requirements_with_hashes(self, input_file: Path, output_file: Path):
        print(f"Generating locked requirements with hashes from {input_file}...")
        
        if not input_file.exists():
            print(f"Error: {input_file} not found")
            sys.exit(1)
        
        temp_venv = self.project_root / ".temp_venv"
        
        try:
            print("Creating temporary virtual environment...")
            subprocess.run(
                [sys.executable, "-m", "venv", str(temp_venv)],
                check=True,
                capture_output=True
            )
            
            if os.name == "nt":
                pip_path = temp_venv / "Scripts" / "pip.exe"
                python_path = temp_venv / "Scripts" / "python.exe"
            else:
                pip_path = temp_venv / "bin" / "pip"
                python_path = temp_venv / "bin" / "python"
            
            print("Upgrading pip...")
            subprocess.run(
                [str(python_path), "-m", "pip", "install", "--upgrade", "pip"],
                check=True,
                capture_output=True
            )
            
            print("Installing dependencies...")
            subprocess.run(
                [str(pip_path), "install", "-r", str(input_file)],
                check=True,
                capture_output=True
            )
            
            print("Generating requirements with hashes...")
            result = subprocess.run(
                [str(pip_path), "freeze"],
                check=True,
                capture_output=True,
                text=True
            )
            
            installed_packages = result.stdout.strip().split("\n")
            
            with open(output_file, "w") as f:
                f.write(f"# Generated on {datetime.now().isoformat()}\n")
                f.write(f"# From: {input_file.name}\n")
                f.write("# DO NOT EDIT MANUALLY - Use dependency manager to update\n\n")
                
                for package in installed_packages:
                    if package and not package.startswith("#"):
                        package_name = package.split("==")[0]
                        
                        hash_result = subprocess.run(
                            [str(pip_path), "hash", package_name],
                            capture_output=True,
                            text=True
                        )
                        
                        if hash_result.returncode == 0:
                            hashes = []
                            for line in hash_result.stdout.split("\n"):
                                if line.strip().startswith("--hash="):
                                    hashes.append(line.strip())
                            
                            f.write(f"{package} \\\n")
                            for hash_line in hashes:
                                f.write(f"    {hash_line}")
                                if hash_line != hashes[-1]:
                                    f.write(" \\")
                                f.write("\n")
                        else:
                            f.write(f"{package}\n")
                        
                        f.write("\n")
            
            print(f"Successfully generated {output_file}")
            
        except subprocess.CalledProcessError as e:
            print(f"Error during dependency installation: {e}")
            if e.stderr:
                print(e.stderr.decode())
            sys.exit(1)
        finally:
            if temp_venv.exists():
                print("Cleaning up temporary environment...")
                import shutil
                shutil.rmtree(temp_venv, ignore_errors=True)
    
    def verify_requirements_hashes(self, requirements_file: Path) -> bool:
        print(f"Verifying hashes in {requirements_file}...")
        
        if not requirements_file.exists():
            print(f"Error: {requirements_file} not found")
            return False
        
        with open(requirements_file, "r") as f:
            content = f.read()
        
        has_hashes = "--hash=" in content
        
        if not has_hashes:
            print("Warning: No hashes found in requirements file")
            return False
        
        packages_with_hashes = 0
        packages_without_hashes = 0
        
        lines = content.split("\n")
        current_package = None
        
        for line in lines:
            line = line.strip()
            if line and not line.startswith("#"):
                if "==" in line and not line.startswith("--hash="):
                    if current_package and "--hash=" not in current_package:
                        packages_without_hashes += 1
                    current_package = line
                elif "--hash=" in line:
                    if current_package:
                        packages_with_hashes += 1
                        current_package = None
        
        print(f"Packages with hashes: {packages_with_hashes}")
        print(f"Packages without hashes: {packages_without_hashes}")
        
        return packages_without_hashes == 0
    
    def install_from_lock(self, lock_file: Path):
        print(f"Installing dependencies from {lock_file}...")
        
        if not lock_file.exists():
            print(f"Error: {lock_file} not found")
            sys.exit(1)
        
        try:
            subprocess.run(
                [sys.executable, "-m", "pip", "install", "-r", str(lock_file), "--require-hashes"],
                check=True
            )
            print("Dependencies installed successfully")
        except subprocess.CalledProcessError as e:
            print(f"Error installing dependencies: {e}")
            sys.exit(1)
    
    def update_dependency(self, package_name: str, version: Optional[str] = None):
        print(f"Updating {package_name}...")
        
        dep_manager = self.detect_dependency_manager()
        
        if dep_manager == "poetry":
            self._update_poetry_dependency(package_name, version)
        else:
            self._update_pip_dependency(package_name, version)
    
    def _update_poetry_dependency(self, package_name: str, version: Optional[str]):
        try:
            if version:
                subprocess.run(
                    ["poetry", "add", f"{package_name}@{version}"],
                    check=True
                )
            else:
                subprocess.run(
                    ["poetry", "update", package_name],
                    check=True
                )
            print(f"Successfully updated {package_name} with Poetry")
        except subprocess.CalledProcessError as e:
            print(f"Error updating with Poetry: {e}")
            sys.exit(1)
    
    def _update_pip_dependency(self, package_name: str, version: Optional[str]):
        if not self.requirements_file.exists():
            print(f"Error: {self.requirements_file} not found")
            sys.exit(1)
        
        with open(self.requirements_file, "r") as f:
            lines = f.readlines()
        
        updated = False
        new_lines = []
        
        for line in lines:
            if line.strip().startswith(package_name):
                if version:
                    new_lines.append(f"{package_name}=={version}\n")
                else:
                    new_lines.append(f"{package_name}\n")
                updated = True
            else:
                new_lines.append(line)
        
        if not updated:
            if version:
                new_lines.append(f"{package_name}=={version}\n")
            else:
                new_lines.append(f"{package_name}\n")
        
        with open(self.requirements_file, "w") as f:
            f.writelines(new_lines)
        
        print(f"Updated {self.requirements_file}")
        print("Regenerating lock file...")
        self.generate_requirements_with_hashes(self.requirements_file, self.requirements_lock)
    
    def check_outdated(self):
        print("Checking for outdated packages...")
        
        dep_manager = self.detect_dependency_manager()
        
        if dep_manager == "poetry":
            try:
                result = subprocess.run(
                    ["poetry", "show", "--outdated"],
                    check=True,
                    capture_output=True,
                    text=True
                )
                print(result.stdout)
            except subprocess.CalledProcessError:
                print("No outdated packages found or Poetry not available")
        else:
            try:
                result = subprocess.run(
                    [sys.executable, "-m", "pip", "list", "--outdated"],
                    check=True,
                    capture_output=True,
                    text=True
                )
                print(result.stdout)
            except subprocess.CalledProcessError as e:
                print(f"Error checking outdated packages: {e}")
    
    def export_poetry_to_requirements(self):
        print("Exporting Poetry dependencies to requirements.txt...")
        
        if not self.poetry_lock.exists():
            print("Error: poetry.lock not found")
            sys.exit(1)
        
        try:
            result = subprocess.run(
                ["poetry", "export", "-f", "requirements.txt", "--output", str(self.requirements_lock), "--with-credentials"],
                check=True,
                capture_output=True,
                text=True
            )
            print(f"Exported to {self.requirements_lock}")
            
            result = subprocess.run(
                ["poetry", "export", "-f", "requirements.txt", "--output", str(self.requirements_dev), "--with", "dev", "--with-credentials"],
                check=True,
                capture_output=True,
                text=True
            )
            print(f"Exported dev dependencies to {self.requirements_dev}")
            
        except subprocess.CalledProcessError as e:
            print(f"Error exporting Poetry dependencies: {e}")
            sys.exit(1)
    
    def audit_security(self):
        print("Running security audit...")
        
        dep_manager = self.detect_dependency_manager()
        
        try:
            subprocess.run(
                [sys.executable, "-m", "pip", "install", "safety"],
                check=True,
                capture_output=True
            )
        except subprocess.CalledProcessError:
            print("Warning: Could not install safety")
        
        try:
            if dep_manager == "poetry":
                result = subprocess.run(
                    ["safety", "check", "--file", str(self.poetry_lock)],
                    capture_output=True,
                    text=True
                )
            else:
                result = subprocess.run(
                    ["safety", "check", "-r", str(self.requirements_lock)],
                    capture_output=True,
                    text=True
                )
            
            print(result.stdout)
            if result.returncode != 0:
                print("Security vulnerabilities found!")
                return False
            else:
                print("No known security vulnerabilities found")
                return True
                
        except subprocess.CalledProcessError as e:
            print(f"Error running security audit: {e}")
            return False
        except FileNotFoundError:
            print("Safety tool not found. Install with: pip install safety")
            return False
    
    def create_dependency_report(self, output_file: str = "dependency_report.json"):
        print("Creating dependency report...")
        
        report = {
            "generated_at": datetime.now().isoformat(),
            "dependency_manager": self.detect_dependency_manager(),
            "packages": []
        }
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "list", "--format", "json"],
                check=True,
                capture_output=True,
                text=True
            )
            
            packages = json.loads(result.stdout)
            
            for package in packages:
                package_info = {
                    "name": package["name"],
                    "version": package["version"]
                }
                
                try:
                    show_result = subprocess.run(
                        [sys.executable, "-m", "pip", "show", package["name"]],
                        check=True,
                        capture_output=True,
                        text=True
                    )
                    
                    for line in show_result.stdout.split("\n"):
                        if line.startswith("License:"):
                            package_info["license"] = line.split(":", 1)[1].strip()
                        elif line.startswith("Home-page:"):
                            package_info["homepage"] = line.split(":", 1)[1].strip()
                        elif line.startswith("Requires:"):
                            package_info["requires"] = line.split(":", 1)[1].strip()
                
                except subprocess.CalledProcessError:
                    pass
                
                report["packages"].append(package_info)
            
            output_path = self.project_root / output_file
            with open(output_path, "w") as f:
                json.dump(report, f, indent=2)
            
            print(f"Dependency report saved to {output_path}")
            
        except subprocess.CalledProcessError as e:
            print(f"Error creating dependency report: {e}")
            sys.exit(1)
    
    def sync_dependencies(self):
        print("Syncing dependencies...")
        
        dep_manager = self.detect_dependency_manager()
        
        if dep_manager == "poetry":
            try:
                subprocess.run(["poetry", "install", "--sync"], check=True)
                print("Dependencies synced with Poetry")
            except subprocess.CalledProcessError as e:
                print(f"Error syncing with Poetry: {e}")
                sys.exit(1)
        else:
            if self.requirements_lock.exists():
                self.install_from_lock(self.requirements_lock)
            else:
                print("No lock file found. Generate one first with: generate-lock")
                sys.exit(1)


def main():
    parser = argparse.ArgumentParser(
        description="Python Dependency Management Tool",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  %(prog)s generate-lock              Generate requirements.lock with hashes
  %(prog)s verify                     Verify hashes in lock file
  %(prog)s install                    Install from lock file
  %(prog)s update requests            Update specific package
  %(prog)s update requests 2.28.0     Update to specific version
  %(prog)s check-outdated             Check for outdated packages
  %(prog)s audit                      Run security audit
  %(prog)s sync                       Sync dependencies with lock file
  %(prog)s report                     Generate dependency report
  %(prog)s poetry-export              Export Poetry deps to requirements.txt
        """
    )
    
    parser.add_argument(
        "command",
        choices=[
            "generate-lock", "verify", "install", "update",
            "check-outdated", "audit", "sync", "report", "poetry-export"
        ],
        help="Command to execute"
    )
    
    parser.add_argument(
        "package",
        nargs="?",
        help="Package name (for update command)"
    )
    
    parser.add_argument(
        "version",
        nargs="?",
        help="Package version (for update command)"
    )
    
    parser.add_argument(
        "--project-root",
        default=".",
        help="Project root directory (default: current directory)"
    )
    
    parser.add_argument(
        "--input",
        help="Input requirements file (for generate-lock)"
    )
    
    parser.add_argument(
        "--output",
        help="Output lock file (for generate-lock)"
    )
    
    args = parser.parse_args()
    
    manager = DependencyManager(args.project_root)
    
    if args.command == "generate-lock":
        input_file = Path(args.input) if args.input else manager.requirements_file
        output_file = Path(args.output) if args.output else manager.requirements_lock
        manager.generate_requirements_with_hashes(input_file, output_file)
    
    elif args.command == "verify":
        lock_file = Path(args.input) if args.input else manager.requirements_lock
        success = manager.verify_requirements_hashes(lock_file)
        sys.exit(0 if success else 1)
    
    elif args.command == "install":
        lock_file = Path(args.input) if args.input else manager.requirements_lock
        manager.install_from_lock(lock_file)
    
    elif args.command == "update":
        if not args.package:
            print("Error: Package name required for update command")
            sys.exit(1)
        manager.update_dependency(args.package, args.version)
    
    elif args.command == "check-outdated":
        manager.check_outdated()
    
    elif args.command == "audit":
        success = manager.audit_security()
        sys.exit(0 if success else 1)
    
    elif args.command == "sync":
        manager.sync_dependencies()
    
    elif args.command == "report":
        output = args.output if args.output else "dependency_report.json"
        manager.create_dependency_report(output)
    
    elif args.command == "poetry-export":
        manager.export_poetry_to_requirements()


if __name__ == "__main__":
    main()